import{_ as r}from"./chunks/ScaleDisplay.vue_vue_type_script_setup_true_lang.BXLvQvzL.js";import{C as l,o as h,c as s,ag as a,E as e,w as o}from"./chunks/framework.DLbVeA01.js";import"./chunks/Piano.QhCkvqJz.js";const b=JSON.parse('{"title":"音阶与调式 Scales & Modes","description":"","frontmatter":{},"headers":[],"relativePath":"scales/index.md","filePath":"scales/index.md"}'),i={name:"scales/index.md"},f=Object.assign(i,{setup(n){return(c,t)=>{const d=l("ClientOnly");return h(),s("div",null,[t[0]||(t[0]=a('<h1 id="音阶与调式-scales-modes" tabindex="-1">音阶与调式 Scales &amp; Modes <a class="header-anchor" href="#音阶与调式-scales-modes" aria-label="Permalink to &quot;音阶与调式 Scales &amp; Modes&quot;">​</a></h1><p><strong>音阶</strong>（Scale）是按特定音程模式排列的一组音符。音阶是旋律和和声的&quot;调色板&quot; — 它决定了一首曲子有哪些音可用。</p><h2 id="什么是音阶" tabindex="-1">什么是音阶？ <a class="header-anchor" href="#什么是音阶" aria-label="Permalink to &quot;什么是音阶？&quot;">​</a></h2><p>音阶就是从一个音（根音）出发，按照特定的&quot;半音-全音&quot;排列规则，走到高八度的同名音。</p><h2 id="交互式音阶展示" tabindex="-1">交互式音阶展示 <a class="header-anchor" href="#交互式音阶展示" aria-label="Permalink to &quot;交互式音阶展示&quot;">​</a></h2><p>选择根音和音阶类型，在钢琴上看到并听到：</p>',6)),e(d,null,{default:o(()=>[e(r)]),_:1}),t[1]||(t[1]=a('<h2 id="常见音阶类型" tabindex="-1">常见音阶类型 <a class="header-anchor" href="#常见音阶类型" aria-label="Permalink to &quot;常见音阶类型&quot;">​</a></h2><h3 id="七声音阶-7-个音" tabindex="-1">七声音阶（7 个音） <a class="header-anchor" href="#七声音阶-7-个音" aria-label="Permalink to &quot;七声音阶（7 个音）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>音程模式</th><th>特点</th></tr></thead><tbody><tr><td><a href="/scales/major.html">大调</a></td><td>W-W-H-W-W-W-H</td><td>最基础，明亮积极</td></tr><tr><td><a href="/scales/natural-minor.html">自然小调</a></td><td>W-H-W-W-H-W-W</td><td>大调的&quot;忧郁版&quot;</td></tr><tr><td><a href="/scales/harmonic-melodic.html">和声小调</a></td><td>W-H-W-W-H-W½-H</td><td>异域风情</td></tr><tr><td><a href="/scales/harmonic-melodic.html">旋律小调</a></td><td>W-H-W-W-W-W-H</td><td>爵士常用</td></tr></tbody></table><h3 id="教会调式-7-个音" tabindex="-1">教会调式（7 个音） <a class="header-anchor" href="#教会调式-7-个音" aria-label="Permalink to &quot;教会调式（7 个音）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>基于大调</th><th>特点</th></tr></thead><tbody><tr><td><a href="/scales/modes.html">多利亚</a></td><td>第 2 音开始</td><td>小调但更明亮</td></tr><tr><td><a href="/scales/modes.html">弗里几亚</a></td><td>第 3 音开始</td><td>异域、西班牙风</td></tr><tr><td><a href="/scales/modes.html">利底亚</a></td><td>第 4 音开始</td><td>梦幻、飘浮</td></tr><tr><td><a href="/scales/modes.html">混合利底亚</a></td><td>第 5 音开始</td><td>摇滚、布鲁斯</td></tr></tbody></table><h3 id="五声与特殊音阶" tabindex="-1">五声与特殊音阶 <a class="header-anchor" href="#五声与特殊音阶" aria-label="Permalink to &quot;五声与特殊音阶&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>音数</th><th>特点</th></tr></thead><tbody><tr><td><a href="/scales/pentatonic.html">大调五声</a></td><td>5</td><td>民歌、即兴万能</td></tr><tr><td><a href="/scales/pentatonic.html">小调五声</a></td><td>5</td><td>摇滚、布鲁斯即兴</td></tr><tr><td><a href="/scales/blues.html">布鲁斯</a></td><td>6</td><td>蓝调特有的色彩</td></tr><tr><td><a href="/scales/chromatic.html">半音阶</a></td><td>12</td><td>所有 12 个半音</td></tr></tbody></table><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="/intervals/">音程</a> — 音阶由音程模式构成</li><li><a href="/chords/">和弦</a> — 音阶内的和弦（顺阶和弦）</li><li><a href="/keys/">调性与五度圈</a> — 调性系统（即将推出）</li></ul>',9))])}}});export{b as __pageData,f as default};
